DELIMITER $$
CREATE TRIGGER `tr_actualizar_costo_producto` AFTER UPDATE ON `formulaciones` FOR EACH ROW BEGIN
  IF NEW.es_activa = TRUE THEN
    UPDATE productos 
    SET costo_produccion = NEW.costo_total
    WHERE id = NEW.producto_id;
  END IF;
END
$$
DELIMITER ;

