--
-- Disparadores `movimientos_productos`
--
DELIMITER $$
CREATE TRIGGER `tr_actualizar_stock_producto` AFTER INSERT ON `movimientos_productos` FOR EACH ROW BEGIN
  UPDATE productos 
  SET stock_actual = NEW.stock_nuevo
  WHERE id = NEW.producto_id;
END
$$
DELIMITER ;

