DELIMITER $$
CREATE TRIGGER `tr_preorden_folio` BEFORE INSERT ON `preordenes` FOR EACH ROW BEGIN
  DECLARE v_num INT;
  SELECT COALESCE(MAX(id), 0) + 1 INTO v_num FROM preordenes;
  SET NEW.folio = CONCAT('PRE-', YEAR(NOW()), '-', LPAD(v_num, 4, '0'));
END
$$
DELIMITER ;

