--
-- Estructura para la vista `v_bom_nivel1`
--
DROP TABLE IF EXISTS `v_bom_nivel1`;

CREATE ALGORITHM=UNDEFINED DEFINER=`st32477_chisa`@`localhost` SQL SECURITY DEFINER VIEW `v_bom_nivel1`  AS SELECT `f`.`id` AS `formulacion_id`, `p`.`id` AS `producto_id`, `p`.`nombre` AS `producto_nombre`, `p`.`codigo` AS `producto_codigo`, `df`.`id` AS `detalle_id`, `df`.`tipo_componente` AS `tipo_componente`, coalesce(`i`.`nombre_tecnico`,`psub`.`nombre`) AS `componente_nombre`, coalesce(`i`.`codigo`,`psub`.`codigo`) AS `componente_codigo`, `i`.`tipo` AS `insumo_tipo`, `i`.`producto_id` AS `insumo_producto_id`, `df`.`porcentaje` AS `porcentaje`, `df`.`cantidad` AS `cantidad`, `df`.`grupo_color` AS `grupo_color`, CASE WHEN `i`.`tipo` in ('fabricado','semielaborado') AND `i`.`producto_id` is not null THEN 1 ELSE 0 END AS `es_sub_fabricado` FROM ((((`formulaciones` `f` join `productos` `p` on(`p`.`id` = `f`.`producto_id`)) join `detalle_formulacion` `df` on(`df`.`formulacion_id` = `f`.`id`)) left join `insumos` `i` on(`i`.`id` = `df`.`insumo_id`)) left join `productos` `psub` on(`psub`.`id` = `df`.`producto_id`)) WHERE `f`.`es_activa` = 1 ;

-- --------------------------------------------------------

--
-- Estructura para la vista `v_insumos_fabricados`
--
DROP TABLE IF EXISTS `v_insumos_fabricados`;

CREATE ALGORITHM=UNDEFINED DEFINER=`st32477_chisa`@`localhost` SQL SECURITY DEFINER VIEW `v_insumos_fabricados`  AS SELECT `i`.`id` AS `insumo_id`, `i`.`codigo` AS `insumo_codigo`, `i`.`nombre_tecnico` AS `insumo_nombre`, `i`.`tipo` AS `tipo`, `p`.`id` AS `producto_id`, `p`.`codigo` AS `producto_codigo`, `p`.`nombre` AS `producto_nombre`, `f`.`id` AS `formulacion_id`, `f`.`version` AS `formulacion_version`, `f`.`es_activa` AS `es_activa` FROM ((`insumos` `i` join `productos` `p` on(`p`.`id` = `i`.`producto_id`)) left join `formulaciones` `f` on(`f`.`producto_id` = `p`.`id` and `f`.`es_activa` = 1)) WHERE `i`.`tipo` in ('fabricado','semielaborado') ;

-- --------------------------------------------------------

--
-- Estructura para la vista `v_stock_insumos_vs_formulaciones`
--
DROP TABLE IF EXISTS `v_stock_insumos_vs_formulaciones`;

CREATE ALGORITHM=UNDEFINED DEFINER=`st32477_chisa`@`localhost` SQL SECURITY DEFINER VIEW `v_stock_insumos_vs_formulaciones`  AS SELECT `i`.`id` AS `insumo_id`, `i`.`nombre_tecnico` AS `nombre_tecnico`, `i`.`codigo` AS `codigo`, `i`.`stock_actual` AS `stock_actual`, `i`.`unidad_medida` AS `unidad_medida`, `i`.`tipo` AS `tipo`, count(distinct `df`.`formulacion_id`) AS `num_formulaciones_uso`, sum(`df`.`cantidad`) AS `cantidad_total_en_formulaciones` FROM ((`insumos` `i` left join `detalle_formulacion` `df` on(`df`.`insumo_id` = `i`.`id`)) left join `formulaciones` `f` on(`f`.`id` = `df`.`formulacion_id` and `f`.`es_activa` = 1)) WHERE `i`.`estatus` = 'Activo' GROUP BY `i`.`id` ORDER BY `i`.`nombre_tecnico` ASC ;

