(1, 'Contrato Individual Estándar', 'Plantilla por defecto generada automáticamente.', NULL, '#1a3a5c', '<p>CONTRATO INDIVIDUAL DE TRABAJO CONTRATO No. {{version}} Tipo: {{tipo_contrato}} Entre CHISA RECUBRIMIENTOS (en adelante \"LA EMPRESA\") y: NOMBRE: {{nombre_completo}} RFC: {{rfc}} CURP: {{curp}} NSS: {{nss}} CL&Aacute;USULAS: PRIMERA.- PUESTO: {{puesto}} SEGUNDA.- DEPARTAMENTO: {{departamento}} TERCERA.- TIPO DE TRABAJADOR: {{tipo_trabajador}} CUARTA.- SALARIO BASE MENSUAL: {{salario_base_mensual}} QUINTA.- SALARIO BASE DIARIO: {{salario_base_diario}} SEXTA.- TIPO DE N&Oacute;MINA: {{tipo_nomina}} S&Eacute;PTIMA.- JORNADA LABORAL: {{jornada_laboral}} FECHA DE INICIO: {{fecha_inicio}} MOTIVO: {{motivo_cambio}} Fecha de generaci&oacute;n: {{fecha_generacion}}</p>', 1, '2026-01-22 11:43:21', '2026-01-22 19:44:56', NULL, NULL),
(2, 'Contrato actualizado 2026', 'Contrato vigente para 2026', 'assets/uploads/logos/a86b20565105519d0d3b4144b0330906.jpg', '#1a3a5c', '<table style=\"width: 100%; border-bottom: 3px solid {{color_corporativo}}; margin-bottom: 30px; padding-bottom: 15px;\">\r\n<tbody>\r\n<tr>\r\n<td style=\"width: 80px; text-align: left;\">&nbsp;</td>\r\n<td style=\"text-align: center;\">\r\n<h1 style=\"margin: 0; font-size: 18pt; letter-spacing: 1px;\">CHISA RECUBRIMIENTOS</h1>\r\n<p style=\"margin: 4px 0 0; font-size: 9pt; color: #666;\">{{domicilio_empresa}}</p>\r\n<p style=\"margin: 2px 0 0; font-size: 9pt; color: #666;\">RFC: CHI-XXXXXX-XXX | Registro Patronal IMSS: XXXXXXXXX</p>\r\n</td>\r\n<td style=\"width: 80px; text-align: right;\">&nbsp;</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n<h2 style=\"text-align: center;\">CONTRATO INDIVIDUAL DE TRABAJO</h2>\r\n<p>&nbsp;</p>\r\n<p style=\"text-align: justify;\">CONTRATO INDIVIDUAL DE TRABAJO POR TIEMPO <strong>{{tipo_contrato}}</strong> QUE CELEBRAN POR UNA PARTE <strong>CHISA RECUBRIMIENTOS</strong> (EN LO SUCESIVO \"EL PATR&Oacute;N\" O \"LA EMPRESA\") REPRESENTADA EN ESTE ACTO POR SU REPRESENTANTE LEGAL, Y POR LA OTRA PARTE EL C. <strong>{{nombre_completo}}</strong> (EN LO SUCESIVO \"EL TRABAJADOR\") AL TENOR DE LAS SIGUIENTES DECLARACIONES Y CL&Aacute;USULAS:</p>\r\n<h3>DECLARACIONES</h3>\r\n<ol type=\"I\">\r\n<li><strong>DECLARA \"EL PATR&Oacute;N\":</strong><br>Ser una Sociedad Mercantil mexicana, legalmente constituida conforme a las leyes de los Estados Unidos Mexicanos.</li>\r\n<li><strong>DECLARA \"EL TRABAJADOR\":</strong><br>Llamarse como ha quedado escrito, con RFC <strong>{{rfc}}</strong>, CURP <strong>{{curp}}</strong> y NSS <strong>{{nss}}</strong>.</li>\r\n</ol>\r\n<h3>CL&Aacute;USULAS</h3>\r\n<p style=\"text-align: justify;\"><strong>PRIMERA.- RELACI&Oacute;N LABORAL.</strong> \"EL PATR&Oacute;N\" contrata a \"EL TRABAJADOR\" por tiempo <strong>{{tipo_contrato}}</strong> para prestar sus servicios personales y subordinados con el puesto de <strong>{{puesto}}</strong> para el departamento de <strong>{{departamento}}</strong>.</p>\r\n<p style=\"text-align: justify;\"><strong>SEGUNDA.- JORNADA DE TRABAJO.</strong> \"EL TRABAJADOR\" se obliga a prestar sus servicios en una jornada de <strong>{{jornada_laboral}}</strong>, disfrutando de un periodo de descanso para consumir alimentos.</p>\r\n<p style=\"text-align: justify;\"><strong>TERCERA.- LUGAR DE TRABAJO.</strong> \"EL TRABAJADOR\" prestar&aacute; sus servicios en el domicilio de \"EL PATR&Oacute;N\" o en los lugares que &eacute;ste designe de acuerdo a las necesidades operativas.</p>\r\n<p style=\"text-align: justify;\"><strong>CUARTA.- SALARIO.</strong> \"EL TRABAJADOR\" percibir&aacute; un salario mensual bruto de <strong>{{salario_base_mensual}}</strong> ({{salario_base_diario}} diarios), pagadero en moneda nacional de forma <strong>{{tipo_nomina}}</strong>.</p>\r\n<p style=\"text-align: justify;\"><strong>QUINTA.- VACACIONES Y AGUINALDO.</strong> \"EL TRABAJADOR\" tendr&aacute; derecho a disfrutar de un periodo anual de vacaciones pagadas y una prima vacacional, as&iacute; como a un aguinaldo anual, conforme a lo establecido en la Ley Federal del Trabajo.</p>\r\n<p style=\"text-align: justify;\"><strong>SEXTA.- SEGURIDAD SOCIAL.</strong> \"EL TRABAJADOR\" ser&aacute; inscrito ante el Instituto Mexicano del Seguro Social (IMSS) conforme a la legislaci&oacute;n aplicable.</p>\r\n<p style=\"text-align: justify;\"><strong>S&Eacute;PTIMA.- CONFIDENCIALIDAD.</strong> \"EL TRABAJADOR\" se obliga a guardar estricta confidencialidad sobre la informaci&oacute;n, documentos y asuntos de \"LA EMPRESA\" que conozca con motivo de su trabajo.</p>\r\n<p>&nbsp;</p>\r\n<p style=\"text-align: center;\">Le&iacute;do que fue el presente contrato y enteradas las partes de su contenido y alcance legal, lo firman de conformidad en CD. JU&Aacute;REZ, CHIHUAHUA a <strong>{{fecha_generacion}}</strong>.</p>\r\n<p style=\"text-align: center;\">&nbsp;</p>\r\n<p style=\"text-align: center;\"><br><br></p>\r\n<table style=\"width: 100%; border-collapse: collapse; margin-top: 50px;\">\r\n<tbody>\r\n<tr>\r\n<td style=\"width: 45%; text-align: center;\">{{firma_empresa_espacio}}</td>\r\n<td style=\"width: 10%;\">&nbsp;</td>\r\n<td style=\"width: 45%; text-align: center;\">{{firma_empleado_espacio}}</td>\r\n</tr>\r\n</tbody>\r\n</table>', 1, '2026-01-22 12:12:28', '2026-06-27 01:14:28', 1, 'Andrés Molina Enriquez #156, Col. San Pedro Iztacalco, C.P 08220, México CDMX.');
